export default function PromocoesTimeline({ historico, promocoesAnteriores, promocaoAtual, militar, canManage, onRegistrarAtual, onCorrigirPromocao, onRetificarPromocao, onExcluirPromocao, onAbrirPromocaoOrigem }) {
