export default function JisoHistoricoModal({ atestado, open, onClose }) {
  const queryClient = useQueryClient();
  const [tipo, setTipo] = useState('Prorrogação');
  const [dias, setDias] = useState('');
  const [motivo, setMotivo] = useState('');
  const [saving, setSaving] = useState(false);
  const [confirmDeleteIdx, setConfirmDeleteIdx] = useState(null);

  const calcularNovasDatas = () => {
    if (!atestado.data_termino || !dias) return null;
    const diasNum = parseInt(dias);
    if (isNaN(diasNum) || diasNum <= 0) return null;
    const deltaSign = tipo === 'Prorrogação' ? 1 : -1;
    const novaTermino = addDays(parseISO(atestado.data_termino), deltaSign * diasNum);
    const novaRetorno = addDays(novaTermino, 1);
    return {
      nova_data_termino: format(novaTermino, 'yyyy-MM-dd'),
      nova_data_retorno: format(novaRetorno, 'yyyy-MM-dd')
    };
  };

  const novasDatas = calcularNovasDatas();

  const handleSave = async () => {
    if (!novasDatas || !motivo) return;
    setSaving(true);

    const novoRegistro = {
      data_registro: new Date().toISOString().split('T')[0],
      tipo,
      dias_alterados: parseInt(dias),
      nova_data_termino: novasDatas.nova_data_termino,
      nova_data_retorno: novasDatas.nova_data_retorno,
      motivo
    };

    const historicoAtual = atestado.historico_jiso || [];
    await atualizarEscopado('Atestado', atestado.id, {
      data_termino: novasDatas.nova_data_termino,
      data_retorno: novasDatas.nova_data_retorno,
      historico_jiso: [...historicoAtual, novoRegistro]
    });

    queryClient.invalidateQueries({ queryKey: ['atestados'] });
    queryClient.invalidateQueries({ queryKey: ['atestados-dashboard'] });
    setSaving(false);
    setDias('');
    setMotivo('');
    onClose();
  };

  const handleDelete = async (idx) => {
    const historico = [...(atestado.historico_jiso || [])];
    // Reverter o efeito deste registro nas datas
    const entry = historico[idx];
    // Recalcular datas a partir do histórico restante
    const restante = historico.filter((_, i) => i !== idx);
    let novaTermino = atestado.data_inicio;
    // Recalcular data_termino somando dias originais do atestado
    const { addDays: ad, parseISO: pI } = await import('date-fns');
    let base = pI(atestado.data_inicio + 'T00:00:00');
    let termino = ad(base, atestado.dias - 1);
    for (const r of restante) {
      const delta = r.tipo === 'Prorrogação' ? r.dias_alterados : -r.dias_alterados;
      termino = ad(termino, delta);
    }
    const novaDataTermino = format(termino, 'yyyy-MM-dd');
    const novaDataRetorno = format(ad(termino, 1), 'yyyy-MM-dd');

    await atualizarEscopado('Atestado', atestado.id, {
      historico_jiso: restante,
      data_termino: novaDataTermino,
      data_retorno: novaDataRetorno
    });
    queryClient.invalidateQueries({ queryKey: ['atestados'] });
    queryClient.invalidateQueries({ queryKey: ['atestados-dashboard'] });
    setConfirmDeleteIdx(null);
  };

  const formatDate = (d) => {
    if (!d) return '-';
    return format(parseISO(d + 'T00:00:00'), 'dd/MM/yyyy');
  };

  return (
    <>
    <AlertDialog open={confirmDeleteIdx !== null} onOpenChange={() => setConfirmDeleteIdx(null)}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Confirmar exclusão</AlertDialogTitle>
          <AlertDialogDescription>
            Tem certeza que deseja excluir este registro de decisão? As datas do atestado serão recalculadas automaticamente.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel>Cancelar</AlertDialogCancel>
          <AlertDialogAction className="bg-red-600 hover:bg-red-700" onClick={() => handleDelete(confirmDeleteIdx)}>
            Excluir
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-[#1e3a5f]">
            <History className="w-5 h-5" />
            Registrar Decisão da JISO
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          {/* Situação atual */}
          <div className="p-3 bg-slate-50 rounded-lg text-sm space-y-1">
            <p className="text-slate-500">Período atual:</p>
            <p className="font-medium text-slate-800">
              {formatDate(atestado.data_inicio)} → {formatDate(atestado.data_termino)} ({atestado.dias} dias)
            </p>
          </div>

          <div className="space-y-1.5">
            <Label>Tipo de Decisão</Label>
            <Select value={tipo} onValueChange={setTipo}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="Prorrogação">Prorrogação (adicionar dias)</SelectItem>
                <SelectItem value="Cassação">Cassação (reduzir dias)</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-1.5">
            <Label>Quantidade de Dias</Label>
            <Input
              type="number"
              min="1"
              value={dias}
              onChange={e => setDias(e.target.value)}
              placeholder="Ex: 15"
            />
          </div>

          {novasDatas && (
            <div className="p-3 bg-blue-50 border border-blue-200 rounded-lg text-sm space-y-1">
              <p className="text-blue-700 font-medium">Nova data de término:</p>
              <p className="text-blue-900 font-bold">{formatDate(novasDatas.nova_data_termino)}</p>
              <p className="text-blue-700 font-medium mt-1">Nova data de retorno:</p>
              <p className="text-blue-900 font-bold">{formatDate(novasDatas.nova_data_retorno)}</p>
            </div>
          )}

          <div className="space-y-1.5">
            <Label>Motivo / Observação <span className="text-red-500">*</span></Label>
            <Textarea
              value={motivo}
              onChange={e => setMotivo(e.target.value)}
              placeholder="Descreva o motivo da decisão da JISO..."
              rows={3}
            />
          </div>

          {/* Histórico anterior */}
          {atestado.historico_jiso?.length > 0 && (
            <div className="space-y-2">
              <Label className="text-sm text-slate-600">Histórico de Decisões</Label>
              <div className="space-y-2 max-h-48 overflow-y-auto">
                {atestado.historico_jiso.map((h, idx) => (
                  <div key={idx} className="p-2 border rounded text-xs bg-white">
                    <div className="flex items-center justify-between mb-1">
                      <span className={`font-semibold ${h.tipo === 'Prorrogação' ? 'text-blue-700' : 'text-red-700'}`}>
                        {h.tipo} de {h.dias_alterados} dias
                      </span>
                      <div className="flex items-center gap-2">
                        <span className="text-slate-400">{formatDate(h.data_registro)}</span>
                        <button
                          onClick={() => setConfirmDeleteIdx(idx)}
                          className="text-red-400 hover:text-red-600"
                          title="Excluir registro"
                        >
                          <Trash2 className="w-3.5 h-3.5" />
                        </button>
                      </div>
                    </div>
                    <p className="text-slate-600">{h.motivo}</p>
                    <p className="text-slate-400">Novo término: {formatDate(h.nova_data_termino)}</p>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div className="flex gap-3 justify-end pt-2">
            <Button variant="outline" onClick={onClose}>Cancelar</Button>
            <Button
              onClick={handleSave}
              disabled={saving || !novasDatas || !motivo}
              className="bg-[#1e3a5f] hover:bg-[#2d4a6f]"
            >
              {saving ? 'Salvando...' : (
                <><PlusCircle className="w-4 h-4 mr-2" />Registrar</>
              )}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
    </>
  );
}

import { useEffect } from 'react';
import { useQuery } from '@tanstack/react-query';
import { base44 } from '@/api/base44Client';

/**
 * useCurrentUser — Lote 1A
 * ----------------------------------------------------------------------------
 * Refatorado para consumir a Deno Function `getUserPermissions` como única
 * fonte de verdade para usuário + acesso + perfil + permissões consolidadas.
 *
 * Removidas as seguintes chamadas diretas ao SDK:
 *   - base44.entities.UsuarioAcesso.filter
 *   - base44.entities.UsuarioAcesso.list  (fallback)
 *   - base44.entities.UsuarioAcesso.get
 *   - base44.entities.PerfilPermissao.get
 *   - base44.entities.PerfilPermissao.filter
 *
 * Mantida a chamada a base44.entities.Subgrupamento.filter apenas para
 * compor unidadesFilhas no escopo "subsetor" (consumida por GlobalMilitarSearch
 * e MilitarSelector via getMilitarScopeFilters). Esta é uma chamada leve por
 * subgrupamento e está fora do escopo do Lote 1A.
 *
 * A API pública do hook (campos retornados) foi preservada integralmente.
 * ----------------------------------------------------------------------------
 */

const ACCESS_QUERY_STALE_TIME = 5 * 60 * 1000;
const ACCESS_QUERY_GC_TIME = 15 * 60 * 1000;

const SELF_RESTRICTED_SCOPES = new Set(['proprio', 'próprio', 'individual', 'self', 'auto']);

// =====================================================================
// MODO USUÁRIO EFETIVO (impersonação para suporte/teste administrativo)
// ---------------------------------------------------------------------
// `sgp_effective_user_email` é uma PONTE CONTROLADA via sessionStorage.
// É enviada à Deno Function `getUserPermissions` no parâmetro `effectiveEmail`.
//
// IMPORTANTE: a validação real (somente admins reais podem usar esse modo)
// ocorre OBRIGATORIAMENTE no backend. Esta chave de sessionStorage não
// concede privilégio nenhum por si só — se um usuário não-admin a definir
// manualmente, o backend retorna 403.
//
// A barra azul "Você está agindo como..." do preview do Base44 NÃO é lida
// nem usada aqui — ela é uma camada externa que não altera base44.auth.me().
// Para testar o modo usuário efetivo, o admin define manualmente:
//   sessionStorage.setItem('sgp_effective_user_email', 'alguem@dominio.com')
// e em seguida recarrega/atualiza a query.
// =====================================================================
const EFFECTIVE_EMAIL_STORAGE_KEY = 'sgp_effective_user_email';

function readEffectiveEmailFromStorage() {
  if (typeof window === 'undefined' || !window.sessionStorage) return null;
  try {
    const raw = window.sessionStorage.getItem(EFFECTIVE_EMAIL_STORAGE_KEY);
    const trimmed = (raw || '').trim();
    return trimmed ? trimmed.toLowerCase() : null;
  } catch (_e) {
    return null;
  }
}

const toLowerSafe = (value) => (typeof value === 'string' ? value.trim().toLowerCase() : null);

const normalizeAccessMode = (value) => {
  const normalized = toLowerSafe(value);
  if (!normalized) return null;
  if (SELF_RESTRICTED_SCOPES.has(normalized)) return 'proprio';
  if (normalized === 'setor') return 'setor';
  if (normalized === 'subsetor') return 'subsetor';
  if (normalized === 'unidade') return 'unidade';
  if (normalized === 'admin') return 'admin';
  return normalized;
};

// Construtor de objeto de "permissions completas" para admin.
// Mantém compatibilidade com consumidores que verificam `permissions === 'ALL'`
// ou `canAccessAll === true`.
const ALL_PERMISSIONS_SENTINEL = 'ALL';

async function fetchUserPermissions(effectiveEmail) {
  const requestPayload = effectiveEmail ? { effectiveEmail } : {};
  const response = await base44.functions.invoke('getUserPermissions', requestPayload);
  // base44.functions.invoke retorna axios-like: { data, status, headers }
  const payload = response?.data ?? response;

  if (!payload) {
    throw new Error('Resposta vazia da função getUserPermissions');
  }

  if (payload?.error && !payload?.user) {
    const err = new Error(payload.error || 'Falha ao carregar permissões');
    err.status = response?.status || 500;
    throw err;
  }

  return payload;
}

export function useCurrentUser() {
  // Lê effectiveEmail apenas uma vez por montagem do hook.
  // Para mudar o usuário efetivo em runtime, basta atualizar o sessionStorage
  // e invalidar a query (`queryClient.invalidateQueries(['current-user-permissions'])`)
  // ou recarregar a página.
  const effectiveEmailFromStorage = readEffectiveEmailFromStorage();

  const {
    data,
    isLoading,
    isError,
    error,
    refetch,
  } = useQuery({
    queryKey: ['current-user-permissions', effectiveEmailFromStorage || 'self'],
    queryFn: () => fetchUserPermissions(effectiveEmailFromStorage),
    staleTime: ACCESS_QUERY_STALE_TIME,
    gcTime: ACCESS_QUERY_GC_TIME,
    retry: 1,
    refetchOnWindowFocus: false,
    refetchOnMount: false,
  });

  const user = data?.user || null;
  const acessos = Array.isArray(data?.acessos) ? data.acessos : [];
  const acesso = acessos[0] || null; // primeiro registro de acesso ativo
  const perfisMap = data?.perfis || {};
  const perfilAcesso = acesso?.perfil_id ? (perfisMap[acesso.perfil_id] || null) : null;

  // Campos de impersonação vindos do backend (fonte de verdade).
  const isImpersonating = Boolean(data?.isImpersonating);
  const authUserEmail = data?.authUserEmail || null;
  const effectiveUserEmail = data?.effectiveUserEmail || null;

  const scope = data?.scope || { tipo: 'vazio', estruturaIds: [], militarId: null, reason: null };
  const modules = data?.modules || {};
  const actions = data?.actions || {};
  const meta = data?.meta || {};

  const isAdminByRole = Boolean(data?.isAdminByRole);
  const isAdminByAccess = Boolean(data?.isAdminByAccess);
  const isAdmin = Boolean(data?.isAdmin);
  const accessMode = data?.accessMode || (isAdmin ? 'admin' : 'restricted');
  const permissionsResolvedAs = data?.permissionsResolvedAs || (isAdmin ? 'admin' : 'profiles');

  // Compatibilidade com consumidores que tratam superadmin como "acesso total".
  // No backend, isAdmin engloba role admin + acesso admin. Não temos mais um
  // "superadmin" separado: para fins de UI, isAdmin é o nível máximo.
  const superAdmin = isAdmin;
  const hasAbsoluteAccess = isAdmin;

  // Modo de acesso para guards/escopo. Usa scope.tipo do backend quando possível,
  // com fallback para o tipo_acesso do primeiro registro.
  const resolvedTipoAcesso = isAdmin
    ? 'admin'
    : (normalizeAccessMode(scope?.tipo) || normalizeAccessMode(acesso?.tipo_acesso) || 'proprio');

  const modoAcesso = resolvedTipoAcesso;

  // Subgrupamento / escopo organizacional.
  // Para setor/subsetor/unidade, `scope.estruturaIds[0]` é o id principal.
  // Para "proprio", não há subgrupamento.
  const isSelfRestrictedScope = modoAcesso === 'proprio';

  let subgrupamentoId = null;
  let subgrupamentoTipo = null;
  if (!isSelfRestrictedScope && !isAdmin) {
    if (modoAcesso === 'setor') {
      subgrupamentoId = acesso?.grupamento_id || (Array.isArray(scope?.estruturaIds) ? scope.estruturaIds[0] : null) || null;
      subgrupamentoTipo = 'Grupamento';
    } else if (modoAcesso === 'subsetor') {
      subgrupamentoId = acesso?.subgrupamento_id || (Array.isArray(scope?.estruturaIds) ? scope.estruturaIds[0] : null) || null;
      subgrupamentoTipo = 'Subgrupamento';
    } else if (modoAcesso === 'unidade') {
      subgrupamentoId = acesso?.subgrupamento_id || (Array.isArray(scope?.estruturaIds) ? scope.estruturaIds[0] : null) || null;
      subgrupamentoTipo = 'Unidade';
    }
  }

  // userEmail representa o usuário efetivo (impersonado quando aplicável).
  // Para acessar o email do autenticado real, use authUserEmail.
  const userEmail = effectiveUserEmail || user?.email || null;
  const linkedMilitarId = scope?.militarId || acesso?.militar_id || null;
  const linkedMilitarEmail = acesso?.militar_email || null;

  // Carregamento de unidades filhas para escopo "subsetor".
  // Mantido por compatibilidade com getMilitarScopeFilters quando o usuário
  // tem visão de subsetor e precisa enxergar as unidades-filhas.
  // Esta é uma chamada leve e fora do escopo do Lote 1A.
  const requiresUnidades = modoAcesso === 'subsetor' && Boolean(subgrupamentoId);
  const {
    data: unidadesFilhas = [],
    isLoading: loadingUnidades,
    isFetched: fetchedUnidades,
  } = useQuery({
    queryKey: ['unidadesFilhas', subgrupamentoId],
    queryFn: () => base44.entities.Subgrupamento.filter({ tipo: 'Unidade', grupamento_id: subgrupamentoId }),
    enabled: requiresUnidades,
    staleTime: 5 * 60 * 1000,
    refetchOnWindowFocus: false,
  });

  // Estados de erro/carregamento mapeados para a API antiga.
  const isAuthError = isError && (error?.status === 401);
  const isPermissionsError = isError && !isAuthError;
  // hasUserButNoAccess: usuário autenticado mas sem registro de UsuarioAcesso
  // (cenário atendido pelo getUserPermissions que retorna 200 com acessos: [])
  const hasUserButNoAccess = Boolean(
    !isLoading
    && !isError
    && data?.user
    && !isAdmin
    && acessos.length === 0,
  );

  const isAccessError = Boolean(isAuthError || isPermissionsError || hasUserButNoAccess);
  const isPermissionPartialError = false; // backend consolida tudo em uma chamada
  const shouldBlockAccessByPermissionError = false;
  const permissionErrorMessage = isPermissionsError ? (error?.message || 'Falha ao carregar permissões.') : null;

  const accessErrorDetails = {
    critical: {
      auth: Boolean(isAuthError),
      usuarioAcesso: Boolean(isPermissionsError),
      usuarioAcessoBlocking: Boolean(isPermissionsError),
      commonUserWithoutValidAccess: Boolean(hasUserButNoAccess),
    },
    nonCritical: {
      usuarioAcessoCompleto: false,
      perfilPermissao: false,
      perfilPermissaoFatal: false,
      resolvedPermissions: false,
      unidades: Boolean(requiresUnidades && fetchedUnidades === false && !loadingUnidades && !data),
    },
  };

  // isPermissionResolved: indica que getUserPermissions já retornou modules/actions
  // consolidados pelo backend. Independe do carregamento de unidadesFilhas, que
  // afeta apenas escopo organizacional (getMilitarScopeFilters/hasAccess).
  const isPermissionResolved = !isLoading && !isError && Boolean(data);

  // isAccessResolved: contexto completo de acesso/escopo (inclui unidadesFilhas
  // quando o usuário é subsetor). Mantido para compatibilidade com consumidores
  // que dependem do escopo organizacional resolvido.
  const isAccessResolved = isPermissionResolved && (!requiresUnidades || (fetchedUnidades && !loadingUnidades));

  // Função utilitária: testa permissão de módulo.
  // Para admin, retorna true sempre.
  // Para restritos, consulta `modules[modulo]` (chave canônica do backend).
  // Depende apenas de isPermissionResolved — NÃO espera unidadesFilhas.
  const canAccessModule = (modulo) => {
    if (!modulo) return false;
    if (hasAbsoluteAccess) return true;
    if (!isPermissionResolved) return false;
    return modules[modulo] === true;
  };

  const canAccessAction = (acao) => {
    if (!acao) return false;
    if (hasAbsoluteAccess) return true;
    if (!isPermissionResolved) return false;
    return actions[acao] === true;
  };

  // Verificação de escopo por registro (mantida da API anterior).
  const hasAccess = (registro) => {
    if (!registro) return false;
    if (isAdmin) return true;

    if (modoAcesso === 'setor') {
      return (
        registro.grupamento_id === subgrupamentoId
        || registro.subgrupamento_id === subgrupamentoId
      );
    }

    if (modoAcesso === 'subsetor') {
      const scopeIds = [subgrupamentoId, ...(unidadesFilhas || []).map((u) => u.id)];
      return scopeIds.includes(registro.subgrupamento_id);
    }

    if (modoAcesso === 'unidade') {
      return registro.subgrupamento_id === subgrupamentoId;
    }

    if (modoAcesso === 'proprio') {
      return (
        registro.created_by === userEmail
        || registro.militar_email === userEmail
        || registro.email === userEmail
      );
    }

    return false;
  };

  const hasSelfAccess = (registro) => {
    if (!registro) return false;
    if (isAdmin) return true;

    if (linkedMilitarId && registro.id === linkedMilitarId) {
      return true;
    }

    const possibleEmails = [
      registro.email,
      registro.email_particular,
      registro.email_funcional,
      registro.militar_email,
      registro.created_by,
      registro.usuario_email,
    ].filter(Boolean);

    const knownEmails = [userEmail, linkedMilitarEmail].filter(Boolean);
    return knownEmails.some((email) => possibleEmails.includes(email));
  };

  // Filtros de escopo de Militar — preservados para GlobalMilitarSearch,
  // MilitarSelector e demais consumidores até que cada um migre para
  // getScopedMilitares (lotes 1B em diante).
  const getMilitarScopeFilters = () => {
    if (isAdmin) return [];

    if (modoAcesso === 'setor' && subgrupamentoId) {
      return [{ grupamento_id: subgrupamentoId }, { subgrupamento_id: subgrupamentoId }];
    }

    if (modoAcesso === 'subsetor' && subgrupamentoId) {
      return [
        { subgrupamento_id: subgrupamentoId },
        ...(unidadesFilhas || []).map((u) => ({ subgrupamento_id: u.id })),
      ];
    }

    if (modoAcesso === 'unidade' && subgrupamentoId) {
      return [{ subgrupamento_id: subgrupamentoId }];
    }

    if (modoAcesso === 'proprio' && linkedMilitarId) {
      return [{ id: linkedMilitarId }];
    }

    return [];
  };

  const getAccessModeFromUser = (targetUser, targetAcesso = null) => {
    if (targetAcesso) return normalizeAccessMode(targetAcesso.tipo_acesso) || 'proprio';
    if (!targetUser) return 'proprio';
    if (targetUser.role === 'admin' || targetUser.isAdmin === true) return 'admin';
    if (targetUser.subgrupamento_tipo === 'Grupamento') return 'setor';
    if (targetUser.subgrupamento_tipo === 'Subgrupamento') return 'subsetor';
    if (targetUser.subgrupamento_tipo === 'Unidade') return 'unidade';
    return 'proprio';
  };

  // Permissions object: para admin, usar sentinela 'ALL' (compatível com
  // RequireModuleAccess que checa `permissions === 'ALL'`).
  // Para restritos, agregamos modules + actions em um único objeto plano,
  // mantendo as chaves canônicas (com prefixos `acesso_` e `perm_`) e também
  // os aliases sem prefixo (compatibilidade com código legado).
  const permissionsObject = (() => {
    if (hasAbsoluteAccess) return ALL_PERMISSIONS_SENTINEL;
    const flat = {};
    Object.entries(modules).forEach(([key, value]) => {
      const truthy = value === true;
      flat[`acesso_${key}`] = truthy;
      flat[key] = truthy;
    });
    Object.entries(actions).forEach(([key, value]) => {
      const truthy = value === true;
      flat[`perm_${key}`] = truthy;
      flat[key] = truthy;
    });
    return flat;
  })();

  const debugAccess = {
    emailAuthOriginal: authUserEmail || user?.email || null,
    emailNormalizado: userEmail,
    authUserEmail,
    effectiveUserEmail,
    isImpersonating,
    status: {
      currentUser: {
        isLoading,
        isError,
        hasData: Boolean(user),
      },
      auth: {
        isAuthenticated: Boolean(user),
        isImpersonating,
      },
      getUserPermissions: {
        isLoading,
        isError,
        hasData: Boolean(data),
        accessMode,
        permissionsResolvedAs,
      },
    },
    usuarioAcessoEncontradosQuantidade: acessos.length,
    usuarioAcessoEncontradosIds: acessos.map((a) => a?.id).filter(Boolean),
    selectedUsuarioAcessoId: acesso?.id || null,
    duplicatedCount: Math.max(0, acessos.length - 1),
    perfil_id: acesso?.perfil_id || null,
    modulesPermitidos: {
      count: Object.values(modules).filter(Boolean).length,
      lista: Object.entries(modules).filter(([, v]) => v === true).map(([k]) => `acesso_${k}`),
    },
    actionsPermitidas: {
      count: Object.values(actions).filter(Boolean).length,
      lista: Object.entries(actions).filter(([, v]) => v === true).map(([k]) => `perm_${k}`),
    },
    scope,
    meta,
    isAccessError,
    isPermissionPartialError,
    shouldBypassUsuarioAcessoBlocking: false,
    isAuthAdminUser: isAdminByRole,
    accessErrorDetails,
  };

  useEffect(() => {
    if (!import.meta.env.DEV) return;
    if (!isAccessError && !isError) return;
    console.warn('[useCurrentUser] estado de erro de acesso/permissões', {
      email: userEmail,
      isAuthError,
      isPermissionsError,
      hasUserButNoAccess,
      message: error?.message || null,
    });
  }, [isAccessError, isError, isAuthError, isPermissionsError, hasUserButNoAccess, userEmail, error]);

  const refetchAccess = async () => {
    await refetch();
  };

  const resolvedAccessContext = {
    isImpersonating,
    baseEmail: authUserEmail || userEmail,
    effectiveEmail: effectiveUserEmail || userEmail,
    hasAcessoRecord: Boolean(acesso),
    modoAcesso,
    isAdmin,
    isSuperAdmin: superAdmin,
    permissions: permissionsObject,
    canAccessAll: hasAbsoluteAccess,
  };

  return {
    // Núcleo
    user,
    acesso,
    perfilAcesso,
    isAdmin,
    isSuperAdmin: superAdmin,
    permissions: permissionsObject,
    canAccessAll: hasAbsoluteAccess,

    // Estado
    isLoading,
    isAccessError,
    isPermissionPartialError,
    shouldBlockAccessByPermissionError,
    permissionErrorMessage,
    accessErrorDetails,
    debugAccess,
    isAccessResolved,

    // Escopo organizacional
    modoAcesso,
    subgrupamentoId,
    subgrupamentoTipo,
    userEmail,
    linkedMilitarId,
    linkedMilitarEmail,
    unidadesFilhas,

    // Helpers de permissão / escopo
    canAccessModule,
    canAccessAction,
    hasAccess,
    hasSelfAccess,
    getMilitarScopeFilters,
    getAccessModeFromUser,

    // Contexto consolidado
    resolvedAccessContext,
    refetchAccess,
  };
}

import React from 'react';
import { Button } from '@/components/ui/button';
import { Copy } from 'lucide-react';

function sanitizeDebugData(data) {
  try {
    return JSON.parse(JSON.stringify(data, (_key, value) => {
      if (value instanceof Error) {
        return {
          name: value.name,
          message: value.message,
          stack: value.stack ? String(value.stack).split('\n').slice(0, 5).join('\n') : null,
        };
      }
      return value;
    }));
  } catch (_error) {
    return {
      pagina: data?.pagina || 'Desconhecida',
      erroSerializacao: 'Não foi possível serializar o diagnóstico',
      geradoEm: new Date().toISOString(),
    };
  }
}

export default function DataDebugPanel({ debugData, className = '' }) {
  const [copied, setCopied] = React.useState(false);

  if (!debugData) return null;

  const payload = sanitizeDebugData(debugData);
  const jsonText = JSON.stringify(payload, null, 2);

  const handleCopy = async () => {
    try {
      if (navigator?.clipboard?.writeText) {
        await navigator.clipboard.writeText(jsonText);
      } else {
        const textArea = document.createElement('textarea');
        textArea.value = jsonText;
        textArea.setAttribute('readonly', '');
        textArea.style.position = 'absolute';
        textArea.style.left = '-9999px';
        document.body.appendChild(textArea);
        textArea.select();
        document.execCommand('copy');
        document.body.removeChild(textArea);
      }
      setCopied(true);
      window.setTimeout(() => setCopied(false), 1800);
    } catch (error) {
      if (import.meta.env.DEV) {
        console.warn('[DataDebugPanel] Falha ao copiar diagnóstico.', error);
      }
    }
  };

  return (
    <div className={`mt-3 rounded-md border border-dashed border-slate-300 bg-slate-50 p-3 text-left ${className}`}>
      <div className="flex items-center justify-between gap-3">
        <p className="text-xs text-slate-600">
          Diagnóstico técnico para suporte. Não compartilhe com usuários finais.
        </p>
        <Button type="button" size="sm" variant="outline" onClick={handleCopy}>
          <Copy className="mr-2 h-4 w-4" />
          {copied ? 'Copiado!' : 'Copiar diagnóstico de dados'}
        </Button>
      </div>
    </div>
  );
}

