    setLoading(true);
    setFeedback(null);

    try {
      const resultado = await recalcularCadeiaCompleta({
        ferias,
        cadeia,
        queryClient,
      });

      setFeedback({
        type: 'success',
        msg: `Cadeia recalculada. Novo status: ${resultado.status}`,
      });
    } catch (error) {
      setFeedback({
        type: 'error',
        msg: error?.message || 'Erro ao recalcular a cadeia.',
