function normalizarTextoTag(valor) {
  return String(valor || '')
    .normalize('NFD')
    .replace(/[̀-ͯ]/g, '')
    .toLowerCase()
    .trim();
}

function isTagInstitucionalLegada(tag) {
  const nome = normalizarTextoTag(tag?.nome);
  return TERMOS_TAGS_INSTITUCIONAIS.some((termo) => nome.includes(termo));
}

