function formatDate(date) {
  if (!date) return '—';
  try { return new Date(`${String(date).slice(0, 10)}T00:00:00`).toLocaleDateString('pt-BR'); } catch (_e) { return date; }
}

function resumoObservacoes(texto) {
  const raw = String(texto || '').trim();
  if (!raw) return '—';
  return raw.length > 90 ? `${raw.slice(0, 90)}...` : raw;
}

function DetailItem({ label, value }) {
  return (
    <div className="rounded-md border border-slate-200 bg-slate-50 p-3">
      <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">{label}</p>
      <p className="mt-1 break-words text-sm font-medium text-slate-700 whitespace-pre-wrap">{value || '—'}</p>
    </div>
  );
}

export default function ContratosDesignacaoSection({
  contratos = [],
  militares = [],
  matriculas = [],
  militarId,
  isLoading = false,
  canCreate = false,
  canEdit = false,
  canEncerrar = false,
  canCancelar = false,
  canExcluir = false,
  onCreate,
  onUpdate,
  onDelete,
  isSaving = false,
}) {
  const { toast } = useToast();
  const navigate = useNavigate();
  const [modalNovoOpen, setModalNovoOpen] = useState(false);
  const [detalhe, setDetalhe] = useState(null);
  const [edicao, setEdicao] = useState(null);
  const [edicaoBloqueiaCadeia, setEdicaoBloqueiaCadeia] = useState(false);
  const [encerrar, setEncerrar] = useState(null);
  const [cancelar, setCancelar] = useState(null);
  const [excluir, setExcluir] = useState(null);

  const ordenados = useMemo(() => ordenarContratosDesignacao(contratos), [contratos]);
  const ativo = useMemo(() => getContratoAtivoDesignacao(contratos), [contratos]);
  const totalAtivos = useMemo(() => contarContratosAtivosDesignacao(contratos), [contratos]);

  const handleCreate = async (payload) => {
    await onCreate?.(payload);
    setModalNovoOpen(false);
    toast({
      title: 'Contrato de designação cadastrado',
      description: 'Revise os períodos aquisitivos do militar e exclua manualmente apenas os períodos incompatíveis, quando permitido.',
      duration: 10000,
      action: (
        <Button type="button" size="sm" variant="outline" onClick={() => revisarPeriodosMilitar(payload?.militar_id || militarId)}>
          Revisar períodos aquisitivos deste militar
        </Button>
      ),
    });
  };

  const revisarPeriodosMilitar = (idMilitar = militarId) => {
    if (!idMilitar) return;
    navigate(`${createPageUrl('PeriodosAquisitivos')}?militarId=${encodeURIComponent(idMilitar)}`);
  };

  const handleAbrirEdicao = async (contrato) => {
    if (!contrato) return;
    try {
      const periodosComEfeito = await buscarEfeitosContratoEmPeriodos(base44, contrato.id);
      setEdicaoBloqueiaCadeia(periodosComEfeito.length > 0);
      setEdicao(contrato);
    } catch (error) {
      toast({
        title: 'Erro ao verificar efeitos do contrato',
        description: error?.message || 'Não foi possível verificar os períodos aquisitivos antes da edição.',
        variant: 'destructive',
      });
    }
  };

  const handleEdit = async (payload) => {
    if (!edicao?.id) return;
    const periodosComEfeito = await buscarEfeitosContratoEmPeriodos(base44, edicao.id);
    if (periodosComEfeito.length > 0) {
      const campoAlterado = getCampoCadeiaFeriasAlterado(edicao, payload);
      if (campoAlterado) throw new Error(`Campo ${campoAlterado} bloqueado: ${MENSAGEM_CONTRATO_COM_EFEITOS}`);
    }
    await onUpdate?.(edicao.id, {
      ...payload,
      militar_id: edicao.militar_id,
      matricula_militar_id: edicao.matricula_militar_id || payload.matricula_militar_id,
      matricula_designacao: edicao.matricula_designacao || payload.matricula_designacao,
    });
    setEdicao(null);
    setEdicaoBloqueiaCadeia(false);
  };

  const handleUpdate = async (contrato, payload) => {
    if (!contrato?.id) return;
    await onUpdate?.(contrato.id, payload);
    setEncerrar(null);
    setCancelar(null);
  };

  const handleDelete = async (contrato) => {
    if (!contrato?.id) return;
    const periodosComEfeito = await buscarEfeitosContratoEmPeriodos(base44, contrato.id);
    if (periodosComEfeito.length > 0) {
      toast({ title: 'Exclusão bloqueada', description: MENSAGEM_CONTRATO_COM_EFEITOS, variant: 'destructive' });
      return;
    }
    await onDelete?.(contrato.id);
    setExcluir(null);
  };

  return (
    <Card className="shadow-sm md:col-span-2">
      <CardHeader className="pb-2">
        <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-3">
          <div>
            <CardTitle className="text-lg flex items-center gap-2 text-[#1e3a5f]">
              <FileText className="w-5 h-5" /> Contratos de Designação
              <Badge variant="outline">{ordenados.length}</Badge>
            </CardTitle>
            <p className="text-sm text-slate-500 mt-1">
              Registro administrativo próprio do militar. Esta seção não altera matrícula, férias, saldos, Livro, publicações ou geradores automaticamente.
            </p>
          </div>
          <div className="flex flex-wrap gap-2 md:justify-end">
            {canCreate && (
              <Button onClick={() => setModalNovoOpen(true)} className="bg-[#1e3a5f] hover:bg-[#2d4a6f] text-white">
                <Plus className="w-4 h-4 mr-2" />Novo contrato
              </Button>
            )}
            <Button type="button" variant="outline" onClick={() => revisarPeriodosMilitar()}>
              Revisar períodos aquisitivos
            </Button>
          </div>
        </div>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3 text-sm">
          <div className="rounded-md border border-slate-200 bg-slate-50 p-3">
            <p className="text-xs text-slate-500">Total de contratos</p>
            <p className="text-xl font-bold text-slate-800">{ordenados.length}</p>
          </div>
          <div className="rounded-md border border-slate-200 bg-slate-50 p-3 md:col-span-2">
            <p className="text-xs text-slate-500">Contrato ativo</p>
            {ativo ? (
              <div className="mt-1 flex flex-wrap gap-2 items-center">
                <Badge className={getContratoDesignacaoStatusBadge(ativo.status_contrato).className}>Ativo</Badge>
                <span className="font-medium text-slate-700">{formatarContratoDesignacaoResumo(ativo)}</span>
              </div>
            ) : <p className="font-medium text-slate-700">Nenhum contrato ativo</p>}
          </div>
        </div>

        {totalAtivos > 1 && (
          <div className="rounded-md border border-rose-200 bg-rose-50 p-3 text-sm text-rose-700 flex gap-2">
            <AlertTriangle className="w-4 h-4 mt-0.5" /> Há mais de um contrato ativo para este militar. Regularize os lançamentos antes de novas integrações.
          </div>
        )}
        {totalAtivos === 0 && (
          <div className="rounded-md border border-blue-200 bg-blue-50 p-3 text-sm text-blue-700">
            Não há contrato ativo. A data de inclusão original do militar permanece preservada.
          </div>
        )}

        {isLoading ? (
          <div className="rounded-md border border-slate-200 p-4 text-sm text-slate-500">Carregando contratos...</div>
        ) : ordenados.length === 0 ? (
          <div className="rounded-md border border-dashed border-slate-300 p-6 text-center text-sm text-slate-500">
            Nenhum contrato de designação cadastrado para este militar.
          </div>
        ) : (
          <div className="rounded-md border border-slate-200 text-sm">
            <div className="hidden grid-cols-[1fr_1.25fr_1.15fr_0.9fr] gap-3 rounded-t-md bg-slate-50 p-3 text-xs font-semibold uppercase text-slate-500 lg:grid">
              <span>Status / matrícula / datas</span>
              <span>Contrato / boletim / publicação</span>
              <span>Legal / tipo / observações</span>
              <span className="text-right">Ações</span>
            </div>
            <div className="divide-y divide-slate-100">
              {ordenados.map((contrato) => {
                const badge = getContratoDesignacaoStatusBadge(contrato.status_contrato);
                const ativoContrato = normalizarStatusContratoDesignacao(contrato.status_contrato) === 'ativo';
                return (
                  <div key={contrato.id || `${contrato.matricula_designacao}-${contrato.data_inicio_contrato}`} className="grid grid-cols-1 gap-3 p-3 lg:grid-cols-[1fr_1.25fr_1.15fr_0.9fr] lg:items-start">
                    <div className="min-w-0 space-y-1">
                      <p className="text-[11px] font-semibold uppercase text-slate-500 lg:hidden">Status / matrícula / datas</p>
                      <div className="flex flex-wrap items-center gap-2">
                        <Badge className={badge.className}>{badge.label}</Badge>
                        <span className="break-words font-medium text-slate-700">{contrato.matricula_designacao || '—'}</span>
                      </div>
                      <p className="text-xs text-slate-500">Início: {formatDate(contrato.data_inicio_contrato)} • Data-base férias: {formatDate(contrato.data_inclusao_para_ferias || contrato.data_inicio_contrato)}</p>
                      <p className="text-xs text-slate-500">Fim: {formatDate(contrato.data_fim_contrato || contrato.data_encerramento_operacional)}</p>
                    </div>

                    <div className="min-w-0 rounded-md bg-slate-50 p-2 lg:bg-transparent lg:p-0">
                      <p className="text-[11px] font-semibold uppercase text-slate-500 lg:hidden">Contrato / boletim / publicação</p>
                      <p className="break-words font-medium text-slate-800">{contrato.numero_contrato || '—'}</p>
                      <p className="break-words text-xs text-slate-500">Boletim/publicação: {contrato.boletim_publicacao || '—'} • Data publicação: {formatDate(contrato.data_publicacao)}</p>
                    </div>

                    <div className="min-w-0 space-y-1">
                      <p className="text-[11px] font-semibold uppercase text-slate-500 lg:hidden">Legal / tipo / observações</p>
                      <p className="break-words text-slate-700">{contrato.fonte_legal || '—'}</p>
                      <p className="break-words text-xs text-slate-500">Tipo: {contrato.tipo_designacao || '—'}</p>
                      <p className="break-words text-xs leading-5 text-slate-500">Obs.: {resumoObservacoes(contrato.observacoes)}</p>
                    </div>

                    <div className="min-w-0 rounded-md border border-slate-200 bg-white p-2 lg:border-0 lg:p-0">
                      <p className="mb-2 text-[11px] font-semibold uppercase text-slate-500 lg:hidden">Ações</p>
                      <div className="grid grid-cols-2 gap-2 lg:grid-cols-1">
                        <Button size="sm" variant="outline" onClick={() => setDetalhe(contrato)}>Ver detalhes</Button>
                        <Button size="sm" variant="outline" onClick={() => revisarPeriodosMilitar(contrato.militar_id || militarId)}>Revisar períodos aquisitivos</Button>
                        {canEdit && <Button size="sm" variant="outline" onClick={() => handleAbrirEdicao(contrato)}><Edit3 className="mr-1 h-4 w-4" />Editar contrato</Button>}
                        {ativoContrato && canEncerrar && <Button size="sm" variant="outline" onClick={() => setEncerrar(contrato)}>Encerrar</Button>}
                        {canCancelar && normalizarStatusContratoDesignacao(contrato.status_contrato) !== 'cancelado' && <Button size="sm" variant="destructive" onClick={() => setCancelar(contrato)}>Cancelar</Button>}
                        {canExcluir && <Button size="sm" variant="destructive" onClick={() => setExcluir(contrato)}>Excluir contrato</Button>}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        <ContratoDesignacaoModal
          open={modalNovoOpen}
          onOpenChange={setModalNovoOpen}
          militarId={militarId}
          militares={militares}
          matriculas={matriculas}
          onSubmit={handleCreate}
          isSubmitting={isSaving}
        />
        <ContratoDesignacaoModal
          open={Boolean(detalhe)}
          onOpenChange={(open) => !open && setDetalhe(null)}
          militarId={militarId}
          militares={militares}
          matriculas={matriculas}
          contrato={detalhe}
          readOnly
        />
        <ContratoDesignacaoModal
          open={Boolean(edicao)}
          onOpenChange={(open) => { if (!open) { setEdicao(null); setEdicaoBloqueiaCadeia(false); } }}
          militarId={militarId}
          militares={militares}
          matriculas={matriculas}
          contrato={edicao}
          bloqueiaCadeiaFerias={edicaoBloqueiaCadeia}
          onSubmit={handleEdit}
          isSubmitting={isSaving}
        />
        <EncerrarContratoDesignacaoModal
          open={Boolean(encerrar)}
          onOpenChange={(open) => !open && setEncerrar(null)}
          contrato={encerrar}
          onSubmit={handleUpdate}
          isSubmitting={isSaving}
        />
        <CancelarContratoDesignacaoModal
          open={Boolean(cancelar)}
          onOpenChange={(open) => !open && setCancelar(null)}
          contrato={cancelar}
          onSubmit={handleUpdate}
          isSubmitting={isSaving}
        />
        <ExcluirContratoDesignacaoModal
          open={Boolean(excluir)}
          onOpenChange={(open) => !open && setExcluir(null)}
          contrato={excluir}
          onSubmit={handleDelete}
          isSubmitting={isSaving}
        />
      </CardContent>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { base44 } from '@/api/base44Client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { calcularTentativasBulk } from '@/utils/funcoesTags/militarTagsBulk';
import IconeCatalogo from '@/components/funcoes-tags/IconeCatalogo';
import { AlertCircle, Check, Loader2, Search, Tags as TagsIcon, Users, X } from 'lucide-react';
import { resolveTagVisual } from '@/utils/tags/tagPresenter';

function isTagAtiva(tag) {
  return resolveTagVisual(tag).ativo;
}


function isTagAplicavelNoMilitar(tag) {
  const aplicabilidade = String(tag?.aplicabilidade || '').trim().toLowerCase();
  if (!aplicabilidade) return true;
  return aplicabilidade === 'militar' || aplicabilidade === 'todos' || aplicabilidade === 'ambos' || aplicabilidade === '';
}


function getTipoVisual(tag) {
  return String(tag?.tipo_visual || '').trim().toLowerCase() || 'chip';
}

function getTipoVisualPeso(tag) {
  const tipo = getTipoVisual(tag);
  if (tipo === 'destaque') return 0;
  if (tipo === 'chip') return 1;
  return 2;
}

function getTagClassName(tag, selecionada = false) {
  const tipo = getTipoVisual(tag);
  if (tipo === 'destaque') {
    return selecionada
      ? 'border-amber-300 bg-amber-50 text-amber-900 ring-1 ring-amber-200'
      : 'border-amber-200 bg-white text-amber-800 hover:bg-amber-50';
  }
  if (tipo === 'normal') {
    return selecionada
      ? 'border-slate-300 bg-slate-100 text-slate-700'
      : 'border-slate-200 bg-white text-slate-600 hover:bg-slate-50';
  }
  return selecionada
    ? 'border-indigo-300 bg-indigo-50 text-indigo-800'
    : 'border-indigo-200 bg-white text-indigo-700 hover:bg-indigo-50/40';
}
function isGrupoAtivo(grupo) {
  return grupo?.ativo !== false && grupo?.ativa !== false && grupo?.status !== 'inativo';
}

function getGrupoNome(grupo) {
  return grupo?.nome || grupo?.name || 'Sem grupo';
}

function normalizarBusca(valor) {
  return String(valor || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

export default function MilitarTagsBulkPanel({
  open,
  onClose,
  selectedCount,
  selectedMilitares = [],
  tagsAtivas,
  gruposAtivos,
  tagsStatusById = {},
  vinculosTagsAtivos = [],
  onConfirm,
  loading,
  saving = false,
}) {
  const [busca, setBusca] = useState('');
  const [selecionadas, setSelecionadas] = useState([]);
  const [tagsEditadas, setTagsEditadas] = useState([]);
  const [motivo, setMotivo] = useState('');

  const { data: tagsCatalogo = [] } = useQuery({
    queryKey: ['funcoes-tags', 'tags'],
    enabled: open,
    queryFn: () => base44.entities.Tag.list('ordem_exibicao'),
  });
  const { data: gruposCatalogo = [] } = useQuery({
    queryKey: ['funcoes-tags', 'grupos'],
    enabled: open,
    queryFn: () => base44.entities.TagGrupo.list('ordem_exibicao'),
  });

  const fonteTags = tagsCatalogo.length > 0 ? tagsCatalogo : (tagsAtivas || []);

  const fonteGrupos = gruposCatalogo.length > 0 ? gruposCatalogo : (gruposAtivos || []);
  const gruposPorId = useMemo(() => new Map(fonteGrupos.map((grupo) => [String(grupo.id), grupo])), [fonteGrupos]);

  const tagsFiltradas = useMemo(() => {
    const termo = normalizarBusca(busca.trim());

    return fonteTags.filter((tag) => {
      if (!tag || !isTagAtiva(tag) || !isTagAplicavelNoMilitar(tag)) return false;

      const grupoId = resolveTagVisual(tag).grupoId;
      const grupo = grupoId ? gruposPorId.get(String(grupoId)) : null;
      if (grupoId && grupo && !isGrupoAtivo(grupo)) return false;

      const grupoNome = grupo ? getGrupoNome(grupo) : 'Sem grupo';
      if (!termo) return true;

      const textoBusca = normalizarBusca(`${resolveTagVisual(tag).nome} ${resolveTagVisual(tag).emoji} ${grupoNome}`);
      return textoBusca.includes(termo);
    });
  }, [fonteTags, busca, gruposPorId]);

  const grupos = useMemo(() => {
    const mapa = new Map();

    tagsFiltradas.forEach((tag) => {
      const grupoId = resolveTagVisual(tag).grupoId;
      const grupo = grupoId ? gruposPorId.get(String(grupoId)) : null;
      const nomeGrupo = grupo ? getGrupoNome(grupo) : 'Sem grupo';
      if (!mapa.has(nomeGrupo)) mapa.set(nomeGrupo, []);
      mapa.get(nomeGrupo).push(tag);
    });

    const prioridade = ['operacional', 'cursos', 'administrativo', 'sem grupo'];
    return [...mapa.entries()]
      .map(([nome, tags]) => ({ nome, tags: tags.sort((a, b) => getTipoVisualPeso(a) - getTipoVisualPeso(b) || resolveTagVisual(a).nome.localeCompare(resolveTagVisual(b).nome, 'pt-BR')) }))
      .sort((a, b) => {
        const ai = prioridade.indexOf(normalizarBusca(a.nome));
        const bi = prioridade.indexOf(normalizarBusca(b.nome));
        const va = ai === -1 ? 99 : ai;
        const vb = bi === -1 ? 99 : bi;
        if (va !== vb) return va - vb;
        return a.nome.localeCompare(b.nome, 'pt-BR');
      });
  }, [tagsFiltradas, gruposPorId]);

  const tagsSelecionadas = useMemo(() => {
    const ids = new Set(selecionadas.map(String));
    return tagsFiltradas.filter((tag) => ids.has(String(tag.id)));
  }, [selecionadas, tagsFiltradas]);

  const statusEfetivoById = useMemo(() => {
    const selecionadasSet = new Set(selecionadas.map(String));
    const editadasSet = new Set(tagsEditadas.map(String));
    const mapa = {};

    tagsFiltradas.forEach((tag) => {
      const tagId = String(tag.id);
      if (selecionadasSet.has(tagId)) {
        mapa[tagId] = 'all';
        return;
      }

      if (!editadasSet.has(tagId)) {
        mapa[tagId] = tagsStatusById[tagId] || 'none';
        return;
      }

      mapa[tagId] = 'none';
    });

    return mapa;
  }, [tagsFiltradas, tagsStatusById, selecionadas, tagsEditadas]);

  useEffect(() => {
    if (!open) return;
    const iniciais = Object.entries(tagsStatusById)
      .filter(([, status]) => status === 'all')
      .map(([tagId]) => String(tagId));
    setSelecionadas(iniciais);
    setTagsEditadas([]);
  }, [open, tagsStatusById]);

  if (!open) return null;

  const isLocked = loading || saving;

  const toggleTag = (tagId) => {
    setSelecionadas((prev) => prev.includes(tagId) ? prev.filter((id) => id !== tagId) : [...prev, tagId]);
    setTagsEditadas((prev) => prev.includes(tagId) ? prev : [...prev, tagId]);
  };

  return (
    <div className="fixed inset-0 z-50 bg-slate-950/45 backdrop-blur-sm" onClick={isLocked ? undefined : onClose}>
      <div className="absolute right-0 top-0 h-full w-full max-w-[450px] bg-white border-l border-slate-200 shadow-2xl flex flex-col" onClick={(e) => e.stopPropagation()}>
        <div className="px-6 py-5 border-b border-slate-200 flex items-center justify-between bg-white shrink-0">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-100 p-2 rounded-lg text-indigo-600">
              <TagsIcon className="w-5 h-5" />
            </div>
            <h2 className="text-lg font-bold text-slate-800">Gerenciar tags</h2>
          </div>
          <Button variant="ghost" onClick={onClose} disabled={isLocked} className="inline-flex items-center gap-1">Fechar <X className="w-4 h-4" /></Button>
        </div>

        <div className="flex-1 overflow-y-auto bg-slate-50/50 p-6 space-y-6">
          <div className="bg-white border border-slate-200 rounded-xl p-4 shadow-sm">
            <div className="text-xs font-semibold tracking-wider text-slate-500 uppercase mb-3 flex items-center gap-2">
              <Users className="w-4 h-4" />
              Alvos selecionados ({selectedMilitares.length || selectedCount})
            </div>
            <div className="space-y-2">
              {selectedMilitares.slice(0, 3).map((militar) => (
                <div key={militar.id} className="flex items-start justify-between gap-2 border border-slate-100 rounded-lg p-2.5 bg-slate-50/70">
                  <div className="min-w-0">
                    <p className="text-sm font-medium text-slate-700 truncate">{[militar.posto_grad, militar.nome_guerra || militar.nome].filter(Boolean).join(' - ') || militar.nome}</p>
                    <p className="text-xs text-slate-500 truncate">{militar.nome_completo || militar.nome || 'Sem nome completo'}</p>
                  </div>
                  <span className="text-xs text-slate-500 shrink-0">{militar.matricula || '-'}</span>
                </div>
              ))}
              {selectedMilitares.length > 3 && <p className="text-xs text-slate-500">+ {selectedMilitares.length - 3} militares selecionados</p>}
            </div>
          </div>

          <div className="relative">
            <Search className="w-5 h-5 text-slate-400 absolute left-3 top-1/2 -translate-y-1/2" />
            <input
              placeholder="Buscar por nome ou grupo da tag..."
              className="w-full pl-10 pr-4 py-3 bg-white border border-slate-300 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none shadow-sm transition-all"
              value={busca}
              onChange={(e) => setBusca(e.target.value)}
              disabled={isLocked}
            />
          </div>

          {selecionadas.length > 0 && (
            <div className="bg-indigo-50/50 border border-indigo-100 rounded-xl p-4">
              <div className="flex items-center justify-between mb-3">
                <p className="text-xs font-semibold tracking-wider text-indigo-700 uppercase">Tags definidas para ficar em todos</p>
                <span className="text-xs font-medium text-indigo-700">{selecionadas.length}</span>
              </div>
              <div className="flex flex-wrap gap-2">
                {tagsSelecionadas.map((tag) => (
                  <button key={tag.id} type="button" onClick={() => toggleTag(String(tag.id))}
                  disabled={isLocked} className={`inline-flex items-center gap-1.5 px-2.5 py-1.5 rounded-full border text-xs ${getTagClassName(tag, true)}`}>
                    <IconeCatalogo value={resolveTagVisual(tag).emoji} />
                    <span>{resolveTagVisual(tag).nome}</span>
                    <X className="w-3 h-3" />
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="space-y-4">
