function mapearEntityPublicacaoPorModulo(modulo) {
  return modulo === MODULO_LIVRO ? base44.entities.RegistroLivro : base44.entities.PublicacaoExOfficio;
}

function nomeEntidadePorModulo(modulo) {
  return modulo === MODULO_LIVRO ? 'RegistroLivro' : 'PublicacaoExOfficio';
}


function montarResumoEdicaoCamposPublicacao(antes = {}, depois = {}) {
  const campos = ['nota_para_bg', 'numero_bg', 'data_bg'];
  const alterados = campos.filter((campo) => String(antes[campo] || '') !== String(depois[campo] || ''));
  if (!alterados.length) return 'Edição de publicação sem alteração de campos de BG.';
  return `Edição de publicação com alteração em: ${alterados.join(', ')}.`;
}

const TEMPLATE_CONFLITO_MENSAGEM =
  'Conflito de template detectado para este tipo. Verifique os templates cadastrados.';
const PLACEHOLDER_RESIDUAL_REGEX = /{{\s*[\w.]+\s*}}/;
const PLACEHOLDER_RESIDUAL_MENSAGEM =
  'Existem variáveis de template não resolvidas no texto. Revise o template ou os dados antes de publicar.';


function normalizarNumeroOpcional(value) {
  if (value === null || value === undefined) return undefined;
  if (typeof value === 'number') return Number.isFinite(value) ? value : undefined;
  const texto = String(value).trim();
  if (!texto) return undefined;
  const numero = Number(texto.replace(',', '.'));
  return Number.isFinite(numero) ? numero : undefined;
}

function extrairDadosPublicacaoReferencia({ formData = {}, publicacoesDisponiveis = [] } = {}) {
  const referenciaSelecionada = publicacoesDisponiveis.find((p) => p.id === formData.publicacao_referencia_id) || {};
  const registroPublicacao = referenciaSelecionada.publicacao || referenciaSelecionada.registro || {};

  const numeroBg =
    formData.publicacao_referencia_numero_bg ||
    referenciaSelecionada.numero_bg ||
    registroPublicacao.numero_bg ||
    registroPublicacao?.publicacao?.numero_bg ||
    formData.numero_bg_ref ||
    '';

  const dataBg =
    formData.publicacao_referencia_data_bg ||
    referenciaSelecionada.data_bg ||
    registroPublicacao.data_bg ||
    registroPublicacao?.publicacao?.data_bg ||
    formData.data_bg_ref ||
    '';

  const notaRef =
    formData.publicacao_referencia_nota ||
    referenciaSelecionada.nota_para_bg ||
    referenciaSelecionada.nota_ref ||
    registroPublicacao.nota_para_bg ||
    registroPublicacao?.publicacao?.nota_para_bg ||
    formData.nota_ref ||
    '';

  return {
    numero_bg_ref: numeroBg || '-',
    data_bg_ref: dataBg || '-',
    nota_ref: notaRef || '-',
  };
}

const MESES_PT_BR = [
  'janeiro', 'fevereiro', 'março', 'abril', 'maio', 'junho',
  'julho', 'agosto', 'setembro', 'outubro', 'novembro', 'dezembro',
];

function formatarDataExtenso(dataStr) {
  if (!dataStr) return '';
  const valor = String(dataStr).trim();
  if (!valor) return '';
  const isoMatch = valor.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) {
    const [, ano, mes, dia] = isoMatch;
    const mesIndex = Number(mes) - 1;
    if (mesIndex >= 0 && mesIndex < 12) {
      return `${dia} de ${MESES_PT_BR[mesIndex]} de ${ano}`;
    }
  }
  const brMatch = valor.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (brMatch) {
    const [, dia, mes, ano] = brMatch;
    const mesIndex = Number(mes) - 1;
    if (mesIndex >= 0 && mesIndex < 12) {
      return `${dia} de ${MESES_PT_BR[mesIndex]} de ${ano}`;
    }
  }
  return valor;
}

function parseDataBGReferencia(dataStr) {
  if (!dataStr) return null;
  const valor = String(dataStr).trim();
  if (!valor || valor === '-') return null;

  const isoMatch = valor.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (isoMatch) {
    const [, ano, mes, dia] = isoMatch;
    const data = new Date(Number(ano), Number(mes) - 1, Number(dia));
    if (
      data.getFullYear() === Number(ano)
      && data.getMonth() === Number(mes) - 1
      && data.getDate() === Number(dia)
    ) {
      return data;
    }
    return null;
  }

  const brMatch = valor.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (brMatch) {
    const [, dia, mes, ano] = brMatch;
    const data = new Date(Number(ano), Number(mes) - 1, Number(dia));
    if (
      data.getFullYear() === Number(ano)
      && data.getMonth() === Number(mes) - 1
      && data.getDate() === Number(dia)
    ) {
      return data;
    }
  }

  return null;
}


