import React, { useState, useMemo } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { base44 } from '@/api/base44Client';
import { criarEstruturaOrganizacional, atualizarEstruturaOrganizacional, excluirEstruturaOrganizacional } from '@/services/cudEstruturaOrganizacionalClient';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Plus, Pencil, Trash2, Building2, Check, X, ChevronRight, ChevronDown, GitMerge, GitBranch, MapPin } from 'lucide-react';
import { useCurrentUser } from '@/components/auth/useCurrentUser';
import AccessDenied from '@/components/auth/AccessDenied';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

const TIPO_CONFIG = {
  'Setor': { icone: Building2, cor: 'text-blue-700', bgIcone: 'bg-blue-100', bgCard: 'bg-white', label: 'Setor (Nível 1)' },
  'Subsetor': { icone: GitMerge, cor: 'text-indigo-600', bgIcone: 'bg-indigo-50', bgCard: 'bg-slate-50', label: 'Subsetor (Nível 2)' },
  'Unidade': { icone: MapPin, cor: 'text-emerald-600', bgIcone: 'bg-emerald-50', bgCard: 'bg-slate-50/50', label: 'Unidade (Nível 3)' }
};

const TIPO_UI_TO_DB = {
  Setor: 'Grupamento',
  Subsetor: 'Subgrupamento',
  Unidade: 'Unidade',
};

const getParentId = (item = {}) => item.grupamento_id || item.setor_pai_id || item.parent_id || '';

// Aliases para fallback entre nomenclatura antiga (Grupamento/Subgrupamento)
// e nova (Setor/Subsetor). Também considera nível hierárquico quando houver.
const normalizeTipo = (itemOrTipo) => {
  const tipo = typeof itemOrTipo === 'string' ? itemOrTipo : itemOrTipo?.tipo;
  const nivel = typeof itemOrTipo === 'object' ? itemOrTipo?.nivel_hierarquico : undefined;

  if (tipo === 'Setor' || tipo === 'Grupamento') return 'Setor';
  if (tipo === 'Subsetor' || tipo === 'Subgrupamento') return 'Subsetor';
  if (tipo === 'Unidade') return 'Unidade';
  if (nivel === 1) return 'Setor';
  if (nivel === 2) return 'Subsetor';
  if (nivel === 3) return 'Unidade';

  return getParentId(itemOrTipo) ? 'Subsetor' : 'Setor';
};

export default function EstruturaOrganizacional() {
  const queryClient = useQueryClient();
  const { canAccessAction, isLoading: loadingUser, isAccessResolved, canAccessModule } = useCurrentUser();
  const hasEstruturaAccess = canAccessModule('estrutura_organizacional');

  const [editingId, setEditingId] = useState(null);
  const [editData, setEditData] = useState({});
  const [showNew, setShowNew] = useState(false);
  const [newData, setNewData] = useState({ nome: '', sigla: '', descricao: '', tipo: 'Setor', grupamento_id: '' });
  const [expandedNodes, setExpandedNodes] = useState({});
  const [deleteDialog, setDeleteDialog] = useState({ open: false, id: null });

  const { data: todosResponse = [], isLoading } = useQuery({
    queryKey: ['estruturaOrganizacional'],
    queryFn: () => base44.entities.Subgrupamento.list('nome'),
  });

  const todos = useMemo(() => {
    if (Array.isArray(todosResponse)) return todosResponse;
    if (Array.isArray(todosResponse?.items)) return todosResponse.items;
    if (Array.isArray(todosResponse?.data)) return todosResponse.data;
    return [];
  }, [todosResponse]);

  const estrutura = useMemo(() => {
    return todos.map(item => ({ ...item, parentId: getParentId(item), tipoNormalizado: normalizeTipo(item) }));
  }, [todos]);

  const setores = estrutura.filter(s => s.tipoNormalizado === 'Setor');
  const subsetores = estrutura.filter(s => s.tipoNormalizado === 'Subsetor');
  const unidades = estrutura.filter(s => s.tipoNormalizado === 'Unidade');

  const createMutation = useMutation({
    mutationFn: (data) => criarEstruturaOrganizacional(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['estruturaOrganizacional'] });
      setNewData({ nome: '', sigla: '', descricao: '', tipo: 'Setor', grupamento_id: '' });
      setShowNew(false);
    },
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }) => atualizarEstruturaOrganizacional(id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['estruturaOrganizacional'] });
      setEditingId(null);
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (id) => excluirEstruturaOrganizacional(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['estruturaOrganizacional'] });
      setDeleteDialog({ open: false, id: null });
    },
  });

  if (loadingUser || !isAccessResolved) return null;
  if (!hasEstruturaAccess) return <AccessDenied modulo="Estrutura Organizacional" />;
  if (!canAccessAction('gerir_estrutura')) {
    return <AccessDenied modulo="Estrutura Organizacional" />;
  }

  const startEdit = (s) => {
    setEditingId(s.id);
    setEditData({ nome: s.nome, sigla: s.sigla || '', descricao: s.descricao || '', tipo: normalizeTipo(s), grupamento_id: s.parentId || '' });
  };

  const saveEdit = (id) => {
    const parent = estrutura.find(g => g.id === editData.grupamento_id);
    updateMutation.mutate({
      id,
      data: {
        ...editData,
        tipo: TIPO_UI_TO_DB[editData.tipo] || editData.tipo,
        nivel_hierarquico: editData.tipo === 'Setor' ? 1 : editData.tipo === 'Subsetor' ? 2 : 3,
        grupamento_id: editData.tipo === 'Setor' ? '' : (editData.grupamento_id || ''),
        setor_pai_id: editData.tipo === 'Setor' ? '' : (editData.grupamento_id || ''),
        parent_id: editData.tipo === 'Setor' ? '' : (editData.grupamento_id || ''),
        grupamento_nome: parent?.nome || '', // Mapeando parent para manter retrocompatibilidade
      }
    });
  };

  const handleCreate = () => {
    const parent = estrutura.find(g => g.id === newData.grupamento_id);
    createMutation.mutate({
      ...newData,
      tipo: TIPO_UI_TO_DB[newData.tipo] || newData.tipo,
      nivel_hierarquico: newData.tipo === 'Setor' ? 1 : newData.tipo === 'Subsetor' ? 2 : 3,
      grupamento_id: newData.tipo === 'Setor' ? '' : (newData.grupamento_id || ''),
      setor_pai_id: newData.tipo === 'Setor' ? '' : (newData.grupamento_id || ''),
      parent_id: newData.tipo === 'Setor' ? '' : (newData.grupamento_id || ''),
      ativo: true,
      grupamento_nome: parent?.nome || '',
    });
  };

  const toggleExpand = (id) => {
    setExpandedNodes(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const handleDelete = () => {
    if (deleteDialog.id) deleteMutation.mutate(deleteDialog.id);
  };

  const getFilhos = (parentId, nivelTarget) => 
    estrutura.filter(s => s.parentId === parentId && s.tipoNormalizado === nivelTarget);

  const getParentOptions = (tipoFilho) => {
    if (tipoFilho === 'Subsetor') return setores; // Subsetor -> Pai é Setor
    if (tipoFilho === 'Unidade') return subsetores; // Unidade -> Pai é Subsetor
    return []; // Setor não tem pai
  };

  const renderEditForm = (data, setData, parentOptions, onSave, onCancel) => (
    <div className="bg-white border-2 border-indigo-200 rounded-xl p-4 shadow-sm my-2">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-3">
        <Input placeholder="Nome *" value={data.nome} onChange={e => setData(d => ({ ...d, nome: e.target.value }))} className="bg-slate-50" />
        <Input placeholder="Sigla" value={data.sigla} onChange={e => setData(d => ({ ...d, sigla: e.target.value }))} className="bg-slate-50" />
        <Input placeholder="Descrição" value={data.descricao} onChange={e => setData(d => ({ ...d, descricao: e.target.value }))} className="col-span-1 md:col-span-2 bg-slate-50" />

