    <div className="overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-sm"><div className="overflow-x-auto"><table className="min-w-full divide-y divide-slate-200 text-sm"><thead className="bg-slate-50 text-left text-xs font-semibold uppercase tracking-wide text-slate-500"><tr><th className="px-4 py-3">Militar</th><th className="px-4 py-3">Função</th><th className="px-4 py-3">Publicação / processo</th><th className="px-4 py-3">Efeitos</th><th className="px-4 py-3">Status</th>{canManageGratificacoes && <th className="px-4 py-3 text-right">Ações</th>}</tr></thead><tbody className="divide-y divide-slate-100">{gratificacoes.map((item) => <tr key={item.id} className="align-top hover:bg-slate-50/80"><td className="min-w-[14rem] px-4 py-4"><p className="font-semibold text-slate-900">{getNomeMilitarGratificacao(item)}</p><p className="text-xs text-slate-500">{item.posto_graduacao_snapshot || 'Posto/graduação não informado'} · Mat. {getMatriculaGratificacao(item)}</p></td><td className="min-w-[13rem] px-4 py-4"><p className="font-medium text-slate-900">{item.funcao_gratificada || '—'}</p><p className="text-xs text-slate-500">{item.codigo_funcao || 'Código não informado'}</p></td><td className="min-w-[14rem] px-4 py-4"><p className="font-medium text-slate-900">{item.doems_nomeacao_numero || item.doems_dispensa_numero || item.ato_nomeacao_numero || item.ato_dispensa_numero || '—'}</p><p className="text-xs text-slate-500">{item.numero_processo || item.documento_solicitacao || 'Processo/documento não informado'}</p></td><td className="min-w-[10rem] px-4 py-4 text-xs text-slate-600"><p>Início: <span className="font-medium text-slate-800">{formatDate(item.data_inicio_efeitos || item.data_publicacao_nomeacao || item.data_solicitacao)}</span></p><p>Fim: <span className="font-medium text-slate-800">{formatDate(item.data_fim_efeitos || item.data_publicacao_dispensa)}</span></p></td><td className="px-4 py-4"><StatusBadge status={item.status} /></td>{canManageGratificacoes && <td className="px-4 py-4 text-right">
  <div className="flex justify-end gap-2">
  {modoAdmin && (
    <Button type="button" variant="outline" size="sm" className="text-red-600 border-red-200 bg-red-50 hover:bg-red-100" onClick={() => onExcluir(item)}>
      <Trash2 className="h-3.5 w-3.5" /> Excluir
    </Button>
  )}
  {item.status === GRATIFICACAO_STATUS.RASCUNHO ? (
    <>
      <Button type="button" variant="outline" size="sm" onClick={() => onEditRascunho(item)}><Edit className="h-3.5 w-3.5" /> Editar</Button>
      <Button type="button" variant="outline" size="sm" className="text-blue-600 border-blue-200 bg-blue-50 hover:bg-blue-100 hover:text-blue-700" onClick={() => onEnviarDP(item)}>Enviar à DP</Button>
    </>
  ) : item.status === GRATIFICACAO_STATUS.SOLICITADO_DP ? (
    <Button type="button" variant="outline" size="sm" className="text-amber-600 border-amber-200 bg-amber-50 hover:bg-amber-100 hover:text-amber-700" onClick={() => onAguardandoPublicacao(item)}>Aguardando Publicação</Button>
  ) : item.status === GRATIFICACAO_STATUS.AGUARDANDO_PUBLICACAO_NOMEACAO ? (
    <Button type="button" variant="outline" size="sm" className="text-emerald-600 border-emerald-200 bg-emerald-50 hover:bg-emerald-100 hover:text-emerald-700" onClick={() => onRegistrarPublicacao(item)}>Registrar Publicação</Button>
  ) : item.status === GRATIFICACAO_STATUS.NOMEADO_ATIVO ? (
    <Button type="button" variant="outline" size="sm" className="text-red-600 border-red-200 bg-red-50 hover:bg-red-100 hover:text-red-700" onClick={() => onFinalizar(item)}>Finalizar</Button>
  ) : (
    !modoAdmin && <span className="text-xs text-slate-400">—</span>
  )}
  </div>
</td>}</tr>)}</tbody></table></div></div>
  );
}

function CotasTable({ cotas, canManage, onEdit }) {
