  return (
    <div className="overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-sm"><div className="overflow-x-auto"><table className="min-w-full divide-y divide-slate-200 text-sm"><thead className="bg-slate-50 text-left text-xs font-semibold uppercase tracking-wide text-slate-500"><tr><th className="px-4 py-3">Função</th><th className="px-4 py-3">Autorizadas</th><th className="px-4 py-3">Ato / DOEMS</th><th className="px-4 py-3">Vigência</th><th className="px-4 py-3">Status</th>{canManage && <th className="px-4 py-3 text-right">Ações</th>}</tr></thead><tbody className="divide-y divide-slate-100">{cotas.map((cota) => <tr key={cota.id} className="align-top hover:bg-slate-50/80"><td className="px-4 py-4"><p className="font-semibold text-slate-900">{cota.funcao_gratificada || '—'}</p><p className="text-xs text-slate-500">{cota.codigo_funcao || 'Código não informado'}</p></td><td className="px-4 py-4 text-base font-bold text-slate-950">{cota.quantidade_autorizada || 0}</td><td className="px-4 py-4"><p className="font-medium text-slate-900">{cota.ato_autorizativo || '—'}</p><p className="text-xs text-slate-500">{cota.doems_autorizacao_numero || cota.doems_autorizacao_edicao || 'DOEMS não informado'}</p></td><td className="px-4 py-4 text-xs text-slate-600"><p>{formatDate(cota.data_inicio_vigencia)}</p><p>{formatDate(cota.data_fim_vigencia)}</p></td><td className="px-4 py-4"><Badge variant="outline" className="rounded-full bg-slate-50 px-2.5 py-1 text-slate-700">{COTA_STATUS_LABELS[cota.status] || cota.status || '—'}</Badge></td>{canManage && <td className="px-4 py-4 text-right"><Button type="button" variant="outline" size="sm" onClick={() => onEdit(cota)}><Edit className="h-3.5 w-3.5" /> Editar</Button></td>}</tr>)}</tbody></table></div></div>
  );
}

function TiposTable({ tipos, canManage, onEdit }) {
  if (!tipos.length) return <EmptyState message="Nenhum tipo de gratificação cadastrado." />;
  return <div className="grid grid-cols-1 gap-3 md:grid-cols-2 xl:grid-cols-3">{tipos.map((tipo) => <div key={tipo.id} className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm"><div className="flex items-start justify-between gap-3"><div><p className="text-base font-semibold text-slate-900">{tipo.nome || 'Tipo sem nome'}</p><p className="mt-1 text-xs text-slate-500">{tipo.sigla || tipo.codigo || 'Sem sigla/código'}</p></div><Badge variant="outline" className={tipo.ativo === false ? 'border-slate-200 bg-slate-50 text-slate-600' : 'border-emerald-200 bg-emerald-50 text-emerald-700'}>{tipo.ativo === false ? 'Inativo' : 'Ativo'}</Badge></div><p className="mt-3 text-sm text-slate-600">{tipo.descricao || 'Sem descrição informada.'}</p><p className="mt-3 text-xs font-medium uppercase tracking-wide text-slate-500">Nível: {tipo.nivel || 'não informado'}</p>{tipo.observacoes && <p className="mt-2 text-xs text-slate-500">{tipo.observacoes}</p>}{canManage && <Button type="button" variant="outline" size="sm" className="mt-4" onClick={() => onEdit(tipo)}><Edit className="h-3.5 w-3.5" /> Editar tipo</Button>}</div>)}</div>;
