export default function Home() {
  const navigate = useNavigate();
  const [afastamentosPanelOpen, setAfastamentosPanelOpen] = React.useState(false);
  const punicaoEntity = getPunicaoEntity();
  const {
    isAdmin,
    modoAcesso,
    userEmail,
    linkedMilitarId,
    linkedMilitarEmail,
    hasSelfAccess,
    getMilitarScopeFilters,
    isAccessResolved,
  } = useCurrentUser();
  const hoje = new Date();
  hoje.setHours(0, 0, 0, 0);

  const hora = new Date().getHours();
  const saudacao = hora < 12 ? 'Bom dia' : hora < 18 ? 'Boa tarde' : 'Boa noite';
  const dataFormatada = format(new Date(), "EEEE, dd 'de' MMMM 'de' yyyy", { locale: ptBR });

  const { data: militares = [] } = useQuery({
    queryKey: ['militares-ativos', isAdmin, modoAcesso, userEmail, linkedMilitarId, linkedMilitarEmail],
    queryFn: async () => {
      if (isAdmin) {
        const lista = await base44.entities.Militar.list('-created_date');
        return carregarMilitaresComMatriculas(lista);
      }

      if (modoAcesso === 'proprio') {
        const knownEmails = [userEmail, linkedMilitarEmail].filter(Boolean);
        if (!linkedMilitarId && knownEmails.length === 0) return [];

        const requests = [];
        if (linkedMilitarId) requests.push(base44.entities.Militar.filter({ id: linkedMilitarId }, '-created_date'));
        for (const email of knownEmails) {
          requests.push(base44.entities.Militar.filter({ email }, '-created_date'));
          requests.push(base44.entities.Militar.filter({ email_particular: email }, '-created_date'));
          requests.push(base44.entities.Militar.filter({ email_funcional: email }, '-created_date'));
          requests.push(base44.entities.Militar.filter({ created_by: email }, '-created_date'));
          requests.push(base44.entities.Militar.filter({ militar_email: email }, '-created_date'));
        }

        const batches = await Promise.all(requests);
        const ids = new Set();
        const vinculados = batches.flat().filter((m) => {
          if (!hasSelfAccess(m) || ids.has(m.id)) return false;
          ids.add(m.id);
          return true;
        });
        return carregarMilitaresComMatriculas(vinculados);
      }

      const filters = getMilitarScopeFilters();
      if (!filters.length) return [];

      const requests = filters.map((filtro) => base44.entities.Militar.filter(filtro, '-created_date'));
      const batches = await Promise.all(requests);
      const ids = new Set();
      const merged = [];
      for (const militar of batches.flat()) {
        if (!ids.has(militar.id)) {
          ids.add(militar.id);
          merged.push(militar);
        }
      }
      return carregarMilitaresComMatriculas(merged);
    },
    enabled: isAccessResolved,
  });

  const scopedSeedIds = React.useMemo(() => militares.map((militar) => String(militar.id)), [militares]);

  // Lote D3 — Home passa a ser fonte única do escopo de militares do dashboard.
  // Admin mantém escopo global (`scopedIds === null`). Escopos restritos usam os
  // IDs já resolvidos pela lista de militares carregada acima, evitando nova
  // resolução de Militar.filter em paralelo.
  const { ids: scopedIds, isAdmin: scopedIsAdmin, isReady: scopedReady } = useScopedMilitarIds({
    seedIds: scopedSeedIds,
  });
  const dashboardEnabled = isAccessResolved && scopedReady;
  const scopeKey = scopedIsAdmin ? 'admin' : (scopedIds || []).join(',');

  const { data: periodos = [] } = useQuery({
    queryKey: ['periodos-aquisitivos', scopeKey],
    queryFn: async () => {
      if (scopedIsAdmin || scopedIds === null) {
        return base44.entities.PeriodoAquisitivo.list();
      }

      if (!scopedIds?.length) return [];

      try {
        const listaEscopo = await base44.entities.PeriodoAquisitivo.filter({
          militar_id: { in: scopedIds },
        });
        return filtrarPorMilitarIdsPermitidos(listaEscopo, scopedIds);
      } catch (_error) {
        const lista = await base44.entities.PeriodoAquisitivo.list();
        return filtrarPorMilitarIdsPermitidos(lista, scopedIds);
      }
    },
    enabled: dashboardEnabled,
  });

  const { data: atestados = [] } = useQuery({
    queryKey: ['dashboard-atestados', scopeKey],
    queryFn: async () => {
      if (scopedIsAdmin || scopedIds === null) {
        return base44.entities.Atestado.list();
      }
      if (!scopedIds?.length) return [];
      try {
        // ⚡ [Performance]: Use server-side filtering to avoid loading full table for non-admin users
        const listaEscopo = await base44.entities.Atestado.filter({
          militar_id: { in: scopedIds },
        });
        return filtrarPorMilitarIdsPermitidos(listaEscopo, scopedIds);
      } catch (_error) {
        const lista = await base44.entities.Atestado.list();
        return filtrarPorMilitarIdsPermitidos(lista, scopedIds);
      }
    },
    enabled: dashboardEnabled,
  });

  const { data: punicoes = [] } = useQuery({
    queryKey: ['punicoes-ativas', scopeKey],
    queryFn: async () => {
      if (scopedIsAdmin || scopedIds === null) {
        return punicaoEntity.list();
      }
      if (!scopedIds?.length) return [];
      try {
        // ⚡ [Performance]: Use server-side filtering to avoid loading full table for non-admin users
        const listaEscopo = await punicaoEntity.filter({
          militar_id: { in: scopedIds },
        });
        return filtrarPorMilitarIdsPermitidos(listaEscopo, scopedIds);
      } catch (_error) {
        const lista = await punicaoEntity.list();
        return filtrarPorMilitarIdsPermitidos(lista, scopedIds);
      }
    },
    enabled: dashboardEnabled,
  });

  const { data: armamentos = [] } = useQuery({
    queryKey: ['armamentos', scopeKey],
    queryFn: async () => {
      if (scopedIsAdmin || scopedIds === null) {
        return base44.entities.Armamento.list();
      }
      if (!scopedIds?.length) return [];
      try {
        // ⚡ [Performance]: Use server-side filtering to avoid loading full table for non-admin users
        const listaEscopo = await base44.entities.Armamento.filter({
          militar_id: { in: scopedIds },
        });
        return filtrarPorMilitarIdsPermitidos(listaEscopo, scopedIds);
      } catch (_error) {
        const lista = await base44.entities.Armamento.list();
        return filtrarPorMilitarIdsPermitidos(lista, scopedIds);
      }
    },
    enabled: dashboardEnabled,
  });

  const { data: registrosLivro = [] } = useQuery({
    queryKey: ['dashboard-registros-livro', scopeKey],
    queryFn: async () => {
      if (scopedIsAdmin || scopedIds === null) {
        return base44.entities.RegistroLivro.list('-created_date');
      }
      if (!scopedIds?.length) return [];
      try {
        // ⚡ [Performance]: Use server-side filtering to avoid loading full table for non-admin users
        const listaEscopo = await base44.entities.RegistroLivro.filter({
          militar_id: { in: scopedIds },
        }, '-created_date');
        return filtrarPorMilitarIdsPermitidos(listaEscopo, scopedIds);
      } catch (_error) {
        const lista = await base44.entities.RegistroLivro.list('-created_date');
        return filtrarPorMilitarIdsPermitidos(lista, scopedIds);
      }
    },
    enabled: dashboardEnabled,
  });

  const { data: publicacoesExOfficio = [] } = useQuery({
    queryKey: ['dashboard-publicacoes-exofficio', scopeKey],
    queryFn: async () => {
      if (scopedIsAdmin || scopedIds === null) {
        return base44.entities.PublicacaoExOfficio.list('-created_date');
      }

      if (!scopedIds?.length) return [];

      try {
        const listaEscopo = await base44.entities.PublicacaoExOfficio.filter({
          militar_id: { in: scopedIds },
        }, '-created_date');
        return filtrarPorMilitarIdsPermitidos(listaEscopo, scopedIds);
      } catch (_error) {
        const lista = await base44.entities.PublicacaoExOfficio.list('-created_date');
        return filtrarPorMilitarIdsPermitidos(lista, scopedIds);
      }
    },
    enabled: dashboardEnabled,
  });
  const { data: pendenciasComportamento = [] } = useQuery({
    queryKey: ['dashboard-pendencias-comportamento', scopeKey],
    queryFn: async () => {
      if (scopedIsAdmin || scopedIds === null) {
        return base44.entities.PendenciaComportamento.filter({ status_pendencia: 'Pendente' });
      }
      if (!scopedIds?.length) return [];
      try {
        // ⚡ [Performance]: Use server-side filtering to avoid loading full table for non-admin users
        const listaEscopo = await base44.entities.PendenciaComportamento.filter({
          status_pendencia: 'Pendente',
          militar_id: { in: scopedIds },
        });
        return filtrarPorMilitarIdsPermitidos(listaEscopo, scopedIds);
      } catch (_error) {
        const lista = await base44.entities.PendenciaComportamento.filter({ status_pendencia: 'Pendente' });
        return filtrarPorMilitarIdsPermitidos(lista, scopedIds);
      }
    },
    enabled: dashboardEnabled,
  });
  const { data: jisoBundle = { atestados: [], jisos: [], meta: {} } } = useQuery({
    queryKey: ['dashboard-jisos', scopeKey],
    queryFn: async () => {
      return fetchScopedAtestadosBundle();
    },
    enabled: dashboardEnabled,
  });
  const { data: ferias = [] } = useQuery({
    queryKey: ['dashboard-ferias', scopeKey],
    queryFn: async () => {
      if (scopedIsAdmin || scopedIds === null) {
        return base44.entities.Ferias.list('-data_inicio');
      }

      if (!scopedIds?.length) return [];

      try {
        const listaEscopo = await base44.entities.Ferias.filter({
          militar_id: { in: scopedIds },
        }, '-data_inicio');
        return filtrarPorMilitarIdsPermitidos(listaEscopo, scopedIds);
      } catch (_error) {
        const lista = await base44.entities.Ferias.list('-data_inicio');
        return filtrarPorMilitarIdsPermitidos(lista, scopedIds);
      }
    },
    enabled: dashboardEnabled,
  });

  // Alertas de férias por nível
  const feriasPorPeriodoAquisitivo = React.useMemo(() => {
    const mapa = new Map();
    for (const feriasItem of ferias) {
      const periodoId = String(feriasItem?.periodo_aquisitivo_id || '');
      if (!periodoId || feriasItem?.status === 'Cancelada') continue;

      if (!mapa.has(periodoId)) mapa.set(periodoId, []);
      mapa.get(periodoId).push(feriasItem);
    }

    for (const listaFerias of mapa.values()) {
      listaFerias.sort((a, b) => new Date(`${a.data_inicio}T00:00:00`) - new Date(`${b.data_inicio}T00:00:00`));
    }
    return mapa;
  }, [ferias]);

  const formatarDataCurta = (dataIso) => {
    if (!dataIso) return '—';
    const data = new Date(`${dataIso}T00:00:00`);
    if (Number.isNaN(data.getTime())) return dataIso;
    return format(data, 'dd/MM/yyyy');
  };

  const periodosAlerta = periodos.filter(p => {
    if (!p.data_limite_gozo) return false;
    if (p.status === 'Gozado' || p.status === 'Inativo') return false;
    const limite = new Date(p.data_limite_gozo + 'T00:00:00');
    const dias = differenceInDays(limite, hoje);
    return dias >= 0 && dias <= 180;
  }).map(p => {
    const dias = differenceInDays(new Date(p.data_limite_gozo + 'T00:00:00'), hoje);
    const feriasPrevistas = feriasPorPeriodoAquisitivo.get(String(p.id)) || [];
    return {
      ...p,
      diasRestantes: dias,
      nivel: dias <= 30 ? 'critico' : dias <= 60 ? 'atencao' : 'aviso',
      feriasPrevistas,
    };
  }).sort((a, b) => a.diasRestantes - b.diasRestantes);

  const atestadosAtivos = atestados.filter(a => a.status === 'Ativo' || a.status === 'Em Curso');
  const punicoesAtivas = punicoes.filter(p => p.status_punicao === 'Ativa' || p.status_punicao === 'Em Curso');
  const publicacoesUrgentes = React.useMemo(() => {
    return [...publicacoesExOfficio, ...registrosLivro]
      .filter(p => p.status !== 'Publicado' && (p.urgente || p.importante));
  }, [publicacoesExOfficio, registrosLivro]);

  // ⚡ [Performance]: Memoize behavior pendencies and cadastral audit to avoid O(N) recalculations on every render
  const pendenciasComportamentoValidas = React.useMemo(() => (
    filtrarPendenciasComportamentoDashboard(pendenciasComportamento, militares)
  ), [pendenciasComportamento, militares]);

  const inconsistenciasCadastrais = React.useMemo(() => (
    listarInconsistenciasCadastraisDashboard(militares)
  ), [militares]);

  const totalAlertas = periodosAlerta.length + publicacoesUrgentes.length + pendenciasComportamentoValidas.length + inconsistenciasCadastrais.length;
  const afastamentosParciais = React.useMemo(() => {
    return buildAfastamentosVigentes({ atestados, registrosLivro }).length;
  }, [atestados, registrosLivro]);

  const registrosRecentes = registrosLivro.slice(0, 5);
  const jisosAgendadas = React.useMemo(() => {
    return montarAgendaJiso({
      atestados: jisoBundle?.atestados,
      jisos: jisoBundle?.jisos,
      hoje,
    });
  }, [jisoBundle, hoje]);

  const formatarHoraJiso = (jiso) => {
    const horaRaw = jiso.horario_jiso || jiso.horario || jiso.hora_jiso;
    if (!horaRaw) return null;
    if (/^\d{2}:\d{2}/.test(horaRaw)) return horaRaw.slice(0, 5);
    const parsed = new Date(horaRaw);
    if (Number.isNaN(parsed.getTime())) return horaRaw;
    return parsed.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100">
